{
  "name": "Neon Infinity Escape",
  "description": "A high-speed, infinite procedural runner where you control a glowing orb escaping through a cybernetic tunnel. Dodge obstacles, collect power-ups, and survive as speed increases."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
}

export interface Point {
  x: number;
  y: number;
}

export interface Player {
  x: number;
  y: number;
  radius: number;
  velocity: Point;
  speed: number;
  color: string;
  shieldActive: boolean;
  trail: Point[];
}

export enum ObstacleType {
  BLOCK = 'BLOCK',
  MOVING_BLOCK = 'MOVING_BLOCK',
  GAP_WALL = 'GAP_WALL',
}

export interface Obstacle {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  speed: number;
  type: ObstacleType;
  passed: boolean; // Has the player passed this obstacle?
  direction?: number; // For moving blocks: 1 or -1
}

export enum PowerUpType {
  SHIELD = 'SHIELD',
  SCORE_BOOST = 'SCORE_BOOST',
}

export interface PowerUp {
  id: string;
  x: number;
  y: number;
  radius: number;
  type: PowerUpType;
  active: boolean;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

export const GAME_CONFIG = {
  PLAYER_RADIUS: 12,
  PLAYER_SPEED: 8, // Horizontal speed sensitivity
  INITIAL_SCROLL_SPEED: 5,
  MAX_SCROLL_SPEED: 15,
  SPEED_INCREMENT: 0.001, // Speed increase per frame
  OBSTACLE_SPAWN_RATE: 60, // Frames between spawns (approx)
  LANE_COUNT: 5,
  COLORS: {
    PLAYER: '#06b6d4', // cyan-500
    PLAYER_SHIELD: '#22d3ee', // cyan-400
    OBSTACLE: '#f43f5e', // rose-500
    OBSTACLE_GLOW: '#be123c', // rose-700
    POWERUP_SHIELD: '#10b981', // emerald-500
    POWERUP_SCORE: '#a855f7', // purple-500
    BACKGROUND_GRID: '#1e293b', // slate-800
  },
  KEYS: {
    LEFT: ['ArrowLeft', 'a', 'A'],
    RIGHT: ['ArrowRight', 'd', 'D'],
  }
};

import React from 'react';
import { GameState } from '../types';
import { Play, RotateCcw, Shield, Zap } from 'lucide-react';

interface GameOverlayProps {
  gameState: GameState;
  score: number;
  highScore: number;
  onStart: () => void;
  onRestart: () => void;
  hasShield: boolean;
}

export const GameOverlay: React.FC<GameOverlayProps> = ({
  gameState,
  score,
  highScore,
  onStart,
  onRestart,
  hasShield,
}) => {
  return (
    <div className="absolute inset-0 pointer-events-none flex flex-col justify-between p-6 z-10">
      {/* Top HUD */}
      <div className="flex justify-between items-start w-full">
        <div className="flex flex-col">
          <span className="text-cyan-400 text-sm font-bold tracking-wider opacity-80 uppercase">Score</span>
          <span className="text-white text-4xl font-black score-font drop-shadow-[0_0_10px_rgba(6,182,212,0.8)]">
            {Math.floor(score).toLocaleString()}
          </span>
        </div>

        <div className="flex flex-col items-end">
           <span className="text-rose-400 text-xs font-bold tracking-wider opacity-80 uppercase">High Score</span>
           <span className="text-rose-200 text-xl font-bold score-font">
            {highScore.toLocaleString()}
          </span>
        </div>
      </div>

      {/* Status Indicators */}
      {gameState === GameState.PLAYING && (
         <div className="absolute top-20 left-6 flex gap-2">
            <div className={`flex items-center gap-2 px-3 py-1 rounded-full border transition-all duration-300 ${hasShield ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400 opacity-100' : 'bg-slate-800/50 border-slate-700 text-slate-600 opacity-50'}`}>
              <Shield size={16} />
              <span className="text-xs font-bold uppercase">Shield</span>
            </div>
         </div>
      )}

      {/* Center Menus */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-auto">
        {gameState === GameState.MENU && (
          <div className="bg-slate-900/90 backdrop-blur-md p-8 rounded-2xl border border-cyan-500/30 shadow-[0_0_50px_rgba(6,182,212,0.2)] text-center max-w-sm w-full animate-in fade-in zoom-in duration-300">
            <h1 className="text-4xl md:text-5xl font-black text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 to-blue-600 mb-2 score-font italic">
              NEON<br/>ESCAPE
            </h1>
            <p className="text-slate-400 mb-8 text-sm leading-relaxed">
              Navigate the infinite cyber-tunnel. <br/>
              Dodge red blocks. Collect power-ups. <br/>
              <span className="text-cyan-400 font-bold">Tap Left/Right</span> or use <span className="text-cyan-400 font-bold">Arrow Keys</span>.
            </p>
            <button
              onClick={onStart}
              className="group relative w-full px-8 py-4 bg-cyan-600 hover:bg-cyan-500 text-white font-bold rounded-lg transition-all duration-200 shadow-[0_0_20px_rgba(6,182,212,0.5)] hover:shadow-[0_0_30px_rgba(6,182,212,0.7)] overflow-hidden"
            >
              <div className="absolute inset-0 w-full h-full bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:animate-[shimmer_1s_infinite]"></div>
              <div className="flex items-center justify-center gap-3">
                <Play size={24} fill="currentColor" />
                <span className="text-lg tracking-widest score-font">START ENGINE</span>
              </div>
            </button>
          </div>
        )}

        {gameState === GameState.GAME_OVER && (
          <div className="bg-slate-900/95 backdrop-blur-xl p-8 rounded-2xl border-2 border-rose-500/50 shadow-[0_0_50px_rgba(244,63,94,0.3)] text-center max-w-sm w-full animate-in zoom-in-95 duration-300">
            <h2 className="text-4xl font-black text-rose-500 mb-2 score-font tracking-tighter">CRITICAL FAILURE</h2>
            <div className="py-6 space-y-2">
              <p className="text-slate-400 text-sm uppercase tracking-widest">Final Score</p>
              <p className="text-5xl font-black text-white score-font">{Math.floor(score).toLocaleString()}</p>
            </div>
            <button
              onClick={onRestart}
              className="w-full px-8 py-4 bg-rose-600 hover:bg-rose-500 text-white font-bold rounded-lg transition-all duration-200 shadow-[0_0_20px_rgba(244,63,94,0.5)] hover:shadow-[0_0_30px_rgba(244,63,94,0.7)] flex items-center justify-center gap-3"
            >
              <RotateCcw size={24} />
              <span className="text-lg tracking-widest score-font">REBOOT SYSTEM</span>
            </button>
          </div>
        )}
      </div>

      {/* Controls Hint (Mobile/Desktop agnostic) */}
      {gameState === GameState.PLAYING && (
        <div className="absolute bottom-10 left-0 right-0 flex justify-between px-8 opacity-30 pointer-events-none">
             <div className="flex flex-col items-center">
                 <div className="w-16 h-16 rounded-full border-2 border-white flex items-center justify-center">
                    <span className="text-2xl font-bold text-white">&lt;</span>
                 </div>
             </div>
             <div className="flex flex-col items-center">
                 <div className="w-16 h-16 rounded-full border-2 border-white flex items-center justify-center">
                    <span className="text-2xl font-bold text-white">&gt;</span>
                 </div>
             </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, Obstacle, ObstacleType, Particle, Player, Point, PowerUp, PowerUpType } from '../types';
import { GAME_CONFIG } from '../constants';

interface GameCanvasProps {
  setGameState: (state: GameState) => void;
  gameState: GameState;
  score: number;
  setScore: (score: number) => void;
  setHasShield: (hasShield: boolean) => void;
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ 
  gameState, 
  setGameState, 
  score, 
  setScore,
  setHasShield
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Game Loop Refs (Mutable state for performance)
  const requestRef = useRef<number>();
  const lastTimeRef = useRef<number>(0);
  const scrollSpeedRef = useRef<number>(GAME_CONFIG.INITIAL_SCROLL_SPEED);
  const scoreRef = useRef<number>(0);

  // Entities
  const playerRef = useRef<Player>({
    x: 0, 
    y: 0, 
    radius: GAME_CONFIG.PLAYER_RADIUS, 
    velocity: { x: 0, y: 0 }, 
    speed: GAME_CONFIG.PLAYER_SPEED,
    color: GAME_CONFIG.COLORS.PLAYER,
    shieldActive: false,
    trail: []
  });

  const obstaclesRef = useRef<Obstacle[]>([]);
  const powerUpsRef = useRef<PowerUp[]>([]);
  const particlesRef = useRef<Particle[]>([]);

  // Input State
  const keysPressed = useRef<{ [key: string]: boolean }>({});
  const touchX = useRef<number | null>(null);

  // --- Initialization ---

  const initGame = useCallback(() => {
    if (!containerRef.current || !canvasRef.current) return;

    const { width, height } = containerRef.current.getBoundingClientRect();
    canvasRef.current.width = width;
    canvasRef.current.height = height;

    // Reset Player
    playerRef.current = {
      x: width / 2,
      y: height - 150, // Fixed vertical position
      radius: GAME_CONFIG.PLAYER_RADIUS,
      velocity: { x: 0, y: 0 },
      speed: GAME_CONFIG.PLAYER_SPEED,
      color: GAME_CONFIG.COLORS.PLAYER,
      shieldActive: false,
      trail: []
    };

    // Reset Game World
    obstaclesRef.current = [];
    powerUpsRef.current = [];
    particlesRef.current = [];
    scrollSpeedRef.current = GAME_CONFIG.INITIAL_SCROLL_SPEED;
    scoreRef.current = 0;
    setScore(0);
    setHasShield(false);
  }, [setScore, setHasShield]);

  // --- Helper Functions ---

  const spawnObstacle = (width: number) => {
    const laneWidth = width / GAME_CONFIG.LANE_COUNT;
    const typeRoll = Math.random();
    let type = ObstacleType.BLOCK;
    if (scoreRef.current > 500 && typeRoll > 0.7) type = ObstacleType.MOVING_BLOCK;
    if (scoreRef.current > 1000 && typeRoll > 0.9) type = ObstacleType.GAP_WALL;

    const id = Math.random().toString(36).substr(2, 9);
    const y = -100; // Spawn above screen

    if (type === ObstacleType.GAP_WALL) {
       // A wall with a gap
       const gapWidth = laneWidth * 1.5;
       const gapX = Math.random() * (width - gapWidth);

       // Left part
       obstaclesRef.current.push({
         id: `${id}-1`, x: 0, y, width: gapX, height: 40, 
         speed: 0, type, passed: false
       });
       // Right part
       obstaclesRef.current.push({
         id: `${id}-2`, x: gapX + gapWidth, y, width: width - (gapX + gapWidth), height: 40, 
         speed: 0, type, passed: false
       });
    } else if (type === ObstacleType.MOVING_BLOCK) {
      const w = laneWidth * 0.8;
      const x = Math.random() * (width - w);
      obstaclesRef.current.push({
        id, x, y, width: w, height: 40, 
        speed: 2 + Math.random() * 2, type, passed: false,
        direction: Math.random() > 0.5 ? 1 : -1
      });
    } else {
      // Standard Blocks
      const count = Math.floor(Math.random() * 2) + 1; // 1 or 2 blocks
      for(let i=0; i<count; i++) {
         const w = laneWidth * 0.8;
         // Quantize to lanes for easier gameplay
         const lane = Math.floor(Math.random() * GAME_CONFIG.LANE_COUNT);
         const x = (lane * laneWidth) + (laneWidth - w)/2;

         // Avoid overlapping exactly
         if (!obstaclesRef.current.some(o => Math.abs(o.y - y) < 10 && Math.abs(o.x - x) < 10)) {
            obstaclesRef.current.push({
              id: `${id}-${i}`, x, y, width: w, height: 40 + Math.random() * 40, 
              speed: 0, type, passed: false
            });
         }
      }
    }

    // Chance to spawn powerup
    if (Math.random() < 0.1) {
       const pX = Math.random() * (width - 40) + 20;
       const pType = Math.random() > 0.7 ? PowerUpType.SHIELD : PowerUpType.SCORE_BOOST;
       powerUpsRef.current.push({
         id: Math.random().toString(),
         x: pX, y: y - 100, radius: 15,
         type: pType, active: true
       });
    }
  };

  const createParticles = (x: number, y: number, color: string, count: number) => {
    for (let i = 0; i < count; i++) {
      particlesRef.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        life: 1.0,
        color,
        size: Math.random() * 4 + 2
      });
    }
  };

  const checkCollision = (rect: Obstacle, circle: Player) => {
    // Closest point on rectangle to circle center
    const clampX = Math.max(rect.x, Math.min(circle.x, rect.x + rect.width));
    const clampY = Math.max(rect.y, Math.min(circle.y, rect.y + rect.height));

    const dx = circle.x - clampX;
    const dy = circle.y - clampY;

    return (dx * dx + dy * dy) < (circle.radius * circle.radius);
  };

  const checkCircleCollision = (p1: {x: number, y: number, radius: number}, p2: {x: number, y: number, radius: number}) => {
     const dx = p1.x - p2.x;
     const dy = p1.y - p2.y;
     const dist = Math.sqrt(dx*dx + dy*dy);
     return dist < (p1.radius + p2.radius);
  };

  // --- Main Loop ---

  const update = (deltaTime: number, time: number) => {
    if (!canvasRef.current) return;
    const canvas = canvasRef.current;
    const width = canvas.width;
    const height = canvas.height;

    // Increase difficulty
    scrollSpeedRef.current = Math.min(
      GAME_CONFIG.MAX_SCROLL_SPEED, 
      scrollSpeedRef.current + GAME_CONFIG.SPEED_INCREMENT
    );

    scoreRef.current += (scrollSpeedRef.current / 10);
    setScore(scoreRef.current); // Debounce this in production for perf, but okay here for simple UI

    // Update Player Movement
    let dx = 0;
    if (keysPressed.current['ArrowLeft'] || keysPressed.current['a'] || keysPressed.current['A']) dx -= 1;
    if (keysPressed.current['ArrowRight'] || keysPressed.current['d'] || keysPressed.current['D']) dx += 1;

    // Touch Logic
    if (touchX.current !== null) {
       const diff = touchX.current - playerRef.current.x;
       if (Math.abs(diff) > 5) {
          dx = Math.sign(diff);
       }
    }

    // Apply Physics
    playerRef.current.x += dx * playerRef.current.speed;

    // Boundary Checks
    if (playerRef.current.x < playerRef.current.radius) playerRef.current.x = playerRef.current.radius;
    if (playerRef.current.x > width - playerRef.current.radius) playerRef.current.x = width - playerRef.current.radius;

    // Trail Effect
    if (time % 5 === 0) {
      playerRef.current.trail.push({ x: playerRef.current.x, y: playerRef.current.y });
      if (playerRef.current.trail.length > 10) playerRef.current.trail.shift();
    }

    // Update Obstacles
    // Spawn logic based on distance traveled (simulated by frames/speed here)
    if (time % Math.floor(GAME_CONFIG.OBSTACLE_SPAWN_RATE * (5 / scrollSpeedRef.current)) === 0) {
      spawnObstacle(width);
    }

    // Move & Filter Obstacles
    for (let i = obstaclesRef.current.length - 1; i >= 0; i--) {
      const obs = obstaclesRef.current[i];
      obs.y += scrollSpeedRef.current;

      // Horizontal movement for moving blocks
      if (obs.type === ObstacleType.MOVING_BLOCK && obs.direction) {
        obs.x += obs.speed * obs.direction;
        if (obs.x <= 0 || obs.x + obs.width >= width) {
          obs.direction *= -1;
        }
      }

      // Collision Check
      if (checkCollision(obs, playerRef.current)) {
         if (playerRef.current.shieldActive) {
            playerRef.current.shieldActive = false;
            setHasShield(false);
            createParticles(obs.x + obs.width/2, obs.y + obs.height/2, GAME_CONFIG.COLORS.OBSTACLE, 20);
            obstaclesRef.current.splice(i, 1); // Destroy obstacle
            continue;
         } else {
            setGameState(GameState.GAME_OVER);
            createParticles(playerRef.current.x, playerRef.current.y, GAME_CONFIG.COLORS.PLAYER, 50);
            return; // Stop update loop
         }
      }

      // Cleanup off-screen
      if (obs.y > height) {
        obstaclesRef.current.splice(i, 1);
      }
    }

    // Update PowerUps
    for (let i = powerUpsRef.current.length - 1; i >= 0; i--) {
      const p = powerUpsRef.current[i];
      p.y += scrollSpeedRef.current;

      if (checkCircleCollision(playerRef.current, p)) {
        if (p.type === PowerUpType.SHIELD) {
          playerRef.current.shieldActive = true;
          setHasShield(true);
        } else if (p.type === PowerUpType.SCORE_BOOST) {
          scoreRef.current += 500;
          createParticles(p.x, p.y, GAME_CONFIG.COLORS.POWERUP_SCORE, 10);
        }
        powerUpsRef.current.splice(i, 1);
      } else if (p.y > height) {
        powerUpsRef.current.splice(i, 1);
      }
    }

    // Update Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
       const p = particlesRef.current[i];
       p.x += p.vx;
       p.y += p.vy;
       p.life -= 0.02;
       if (p.life <= 0) particlesRef.current.splice(i, 1);
    }
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const width = canvas.width;
    const height = canvas.height;

    // Clear
    ctx.fillStyle = GAME_CONFIG.COLORS.BACKGROUND_GRID;
    ctx.fillRect(0, 0, width, height);

    // Draw Moving Grid (Perspective illusion)
    ctx.strokeStyle = 'rgba(6, 182, 212, 0.1)';
    ctx.lineWidth = 1;
    const gridOffset = (Date.now() / 10 * scrollSpeedRef.current) % 100;

    // Vertical lines
    for (let i = 0; i <= GAME_CONFIG.LANE_COUNT; i++) {
        const x = (width / GAME_CONFIG.LANE_COUNT) * i;
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
        ctx.stroke();
    }

    // Horizontal moving lines
    for (let y = gridOffset - 100; y < height; y += 100) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
    }

    // Draw Particles
    particlesRef.current.forEach(p => {
       ctx.globalAlpha = p.life;
       ctx.fillStyle = p.color;
       ctx.beginPath();
       ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
       ctx.fill();
       ctx.globalAlpha = 1.0;
    });

    // Draw PowerUps
    powerUpsRef.current.forEach(p => {
       ctx.shadowBlur = 15;
       ctx.shadowColor = p.type === PowerUpType.SHIELD ? GAME_CONFIG.COLORS.POWERUP_SHIELD : GAME_CONFIG.COLORS.POWERUP_SCORE;
       ctx.fillStyle = p.type === PowerUpType.SHIELD ? GAME_CONFIG.COLORS.POWERUP_SHIELD : GAME_CONFIG.COLORS.POWERUP_SCORE;
       ctx.beginPath();
       ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
       ctx.fill();

       // Inner Icon (simple)
       ctx.fillStyle = '#fff';
       ctx.font = '12px Arial';
       ctx.textAlign = 'center';
       ctx.textBaseline = 'middle';
       ctx.fillText(p.type === PowerUpType.SHIELD ? 'S' : '+', p.x, p.y);
       ctx.shadowBlur = 0;
    });

    // Draw Obstacles
    obstaclesRef.current.forEach(obs => {
      ctx.shadowBlur = 10;
      ctx.shadowColor = GAME_CONFIG.COLORS.OBSTACLE_GLOW;
      ctx.fillStyle = GAME_CONFIG.COLORS.OBSTACLE;

      // Rounded rects
      ctx.beginPath();
      ctx.roundRect(obs.x, obs.y, obs.width, obs.height, 4);
      ctx.fill();
      ctx.shadowBlur = 0;

      // Detail line
      ctx.fillStyle = 'rgba(255,255,255,0.2)';
      ctx.fillRect(obs.x, obs.y + 5, obs.width, 5);
    });

    // Draw Player Trail
    const player = playerRef.current;
    if (player.trail.length > 1) {
       ctx.beginPath();
       ctx.moveTo(player.trail[0].x, player.trail[0].y);
       for (let i = 1; i < player.trail.length; i++) {
         ctx.lineTo(player.trail[i].x, player.trail[i].y);
       }
       ctx.strokeStyle = `rgba(6, 182, 212, 0.3)`;
       ctx.lineWidth = player.radius;
       ctx.lineCap = 'round';
       ctx.stroke();
    }

    // Draw Player
    ctx.shadowBlur = 20;
    ctx.shadowColor = player.shieldActive ? GAME_CONFIG.COLORS.PLAYER_SHIELD : GAME_CONFIG.COLORS.PLAYER;
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.arc(player.x, player.y, player.radius, 0, Math.PI * 2);
    ctx.fill();

    // Shield glow ring
    if (player.shieldActive) {
       ctx.strokeStyle = GAME_CONFIG.COLORS.PLAYER_SHIELD;
       ctx.lineWidth = 2;
       ctx.beginPath();
       ctx.arc(player.x, player.y, player.radius + 5, 0, Math.PI * 2);
       ctx.stroke();
    }

    ctx.shadowBlur = 0;
  };

  const gameLoop = (time: number) => {
    if (gameState === GameState.PLAYING) {
       const deltaTime = time - lastTimeRef.current;
       lastTimeRef.current = time;
       update(deltaTime, Math.floor(time / 16)); // Pass rough frame count
    }
    draw();
    requestRef.current = requestAnimationFrame(gameLoop);
  };

  // --- Effects ---

  useEffect(() => {
    // Input Listeners
    const handleKeyDown = (e: KeyboardEvent) => keysPressed.current[e.key] = true;
    const handleKeyUp = (e: KeyboardEvent) => keysPressed.current[e.key] = false;

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    // Initial Render
    initGame();
    requestRef.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount

  // Watch for Game Reset
  useEffect(() => {
     if (gameState === GameState.PLAYING && scoreRef.current === 0) {
        initGame();
     }
  }, [gameState, initGame]);

  // Handle Touch
  const handleTouchStart = (e: React.TouchEvent) => {
    touchX.current = e.touches[0].clientX;
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    touchX.current = e.touches[0].clientX;
    // Prevent scrolling logic handled by CSS touch-action: none
  };

  const handleTouchEnd = () => {
    touchX.current = null;
  };

  // Mouse for fallback/desktop
  const handleMouseMove = (e: React.MouseEvent) => {
    if (gameState === GameState.PLAYING) {
       // Optional: Mouse follow mode. For now we use keys, but we could uncomment below:
       // const rect = canvasRef.current?.getBoundingClientRect();
       // if(rect) playerRef.current.x = e.clientX - rect.left;
    }
  }

  return (
    <div ref={containerRef} className="absolute inset-0 w-full h-full bg-slate-900">
      <canvas
        ref={canvasRef}
        className="block w-full h-full touch-none"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
        // onMouseMove={handleMouseMove} // Uncomment for mouse control
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { GameCanvas } from './components/GameCanvas';
import { GameOverlay } from './components/GameOverlay';
import { GameState } from './types';

export default function App() {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [hasShield, setHasShield] = useState(false);

  // Load High Score
  useEffect(() => {
    const saved = localStorage.getItem('neon_escape_highscore');
    if (saved) setHighScore(parseInt(saved, 10));
  }, []);

  // Update High Score
  useEffect(() => {
    if (score > highScore) {
      setHighScore(Math.floor(score));
      localStorage.setItem('neon_escape_highscore', Math.floor(score).toString());
    }
  }, [score, highScore]);

  const handleStart = () => {
    setScore(0);
    setGameState(GameState.PLAYING);
  };

  const handleRestart = () => {
    setScore(0);
    setGameState(GameState.PLAYING);
  };

  return (
    <div className="relative w-full h-screen overflow-hidden bg-slate-950">
      <GameCanvas 
        gameState={gameState} 
        setGameState={setGameState}
        score={score}
        setScore={setScore}
        setHasShield={setHasShield}
      />
      <GameOverlay 
        gameState={gameState} 
        score={score}
        highScore={highScore}
        onStart={handleStart}
        onRestart={handleRestart}
        hasShield={hasShield}
      />
    </div>
  );
}

export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
}

export interface Point {
  x: number;
  y: number;
}

export interface Player {
  x: number;
  y: number;
  radius: number;
  velocity: Point;
  speed: number;
  color: string;
  shieldActive: boolean;
  trail: Point[];
}

export enum ObstacleType {
  BLOCK = 'BLOCK',
  MOVING_BLOCK = 'MOVING_BLOCK',
  GAP_WALL = 'GAP_WALL',
}

export interface Obstacle {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  speed: number;
  type: ObstacleType;
  passed: boolean; // Has the player passed this obstacle?
  direction?: number; // For moving blocks: 1 or -1
}

export enum PowerUpType {
  SHIELD = 'SHIELD',
  SCORE_BOOST = 'SCORE_BOOST',
  SCORE_MULTIPLIER = 'SCORE_MULTIPLIER',
}

export interface PowerUp {
  id: string;
  x: number;
  y: number;
  radius: number;
  type: PowerUpType;
  active: boolean;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

export const GAME_CONFIG = {
  PLAYER_RADIUS: 12,
  PLAYER_SPEED: 8, // Horizontal speed sensitivity
  INITIAL_SCROLL_SPEED: 5,
  MAX_SCROLL_SPEED: 15,
  SPEED_INCREMENT: 0.001, // Speed increase per frame
  OBSTACLE_SPAWN_RATE: 60, // Frames between spawns (approx)
  LANE_COUNT: 5,
  COLORS: {
    PLAYER: '#06b6d4', // cyan-500
    PLAYER_SHIELD: '#22d3ee', // cyan-400
    OBSTACLE: '#f43f5e', // rose-500
    OBSTACLE_GLOW: '#be123c', // rose-700
    POWERUP_SHIELD: '#10b981', // emerald-500
    POWERUP_SCORE: '#a855f7', // purple-500
    POWERUP_MULTIPLIER: '#fbbf24', // amber-400
    BACKGROUND_GRID: '#1e293b', // slate-800
  },
  KEYS: {
    LEFT: ['ArrowLeft', 'a', 'A'],
    RIGHT: ['ArrowRight', 'd', 'D'],
  }
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, Obstacle, ObstacleType, Particle, Player, Point, PowerUp, PowerUpType } from '../types';
import { GAME_CONFIG } from '../constants';

interface GameCanvasProps {
  setGameState: (state: GameState) => void;
  gameState: GameState;
  score: number;
  setScore: (score: number) => void;
  setHasShield: (hasShield: boolean) => void;
  setScoreMultiplier: (multiplier: number) => void;
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ 
  gameState, 
  setGameState, 
  score, 
  setScore,
  setHasShield,
  setScoreMultiplier
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Game Loop Refs (Mutable state for performance)
  const requestRef = useRef<number>();
  const lastTimeRef = useRef<number>(0);
  const scrollSpeedRef = useRef<number>(GAME_CONFIG.INITIAL_SCROLL_SPEED);
  const scoreRef = useRef<number>(0);
  const scoreMultiplierRef = useRef<number>(1);
  const multiplierEndFrameRef = useRef<number>(0);

  // Entities
  const playerRef = useRef<Player>({
    x: 0, 
    y: 0, 
    radius: GAME_CONFIG.PLAYER_RADIUS, 
    velocity: { x: 0, y: 0 }, 
    speed: GAME_CONFIG.PLAYER_SPEED,
    color: GAME_CONFIG.COLORS.PLAYER,
    shieldActive: false,
    trail: []
  });

  const obstaclesRef = useRef<Obstacle[]>([]);
  const powerUpsRef = useRef<PowerUp[]>([]);
  const particlesRef = useRef<Particle[]>([]);

  // Input State
  const keysPressed = useRef<{ [key: string]: boolean }>({});
  const touchX = useRef<number | null>(null);

  // --- Initialization ---

  const initGame = useCallback(() => {
    if (!containerRef.current || !canvasRef.current) return;

    const { width, height } = containerRef.current.getBoundingClientRect();
    canvasRef.current.width = width;
    canvasRef.current.height = height;

    // Reset Player
    playerRef.current = {
      x: width / 2,
      y: height - 150, // Fixed vertical position
      radius: GAME_CONFIG.PLAYER_RADIUS,
      velocity: { x: 0, y: 0 },
      speed: GAME_CONFIG.PLAYER_SPEED,
      color: GAME_CONFIG.COLORS.PLAYER,
      shieldActive: false,
      trail: []
    };

    // Reset Game World
    obstaclesRef.current = [];
    powerUpsRef.current = [];
    particlesRef.current = [];
    scrollSpeedRef.current = GAME_CONFIG.INITIAL_SCROLL_SPEED;
    scoreRef.current = 0;
    scoreMultiplierRef.current = 1;
    multiplierEndFrameRef.current = 0;
    setScore(0);
    setHasShield(false);
    setScoreMultiplier(1);
  }, [setScore, setHasShield, setScoreMultiplier]);

  // --- Helper Functions ---

  const spawnObstacle = (width: number) => {
    const laneWidth = width / GAME_CONFIG.LANE_COUNT;
    const typeRoll = Math.random();
    let type = ObstacleType.BLOCK;
    if (scoreRef.current > 500 && typeRoll > 0.7) type = ObstacleType.MOVING_BLOCK;
    if (scoreRef.current > 1000 && typeRoll > 0.9) type = ObstacleType.GAP_WALL;

    const id = Math.random().toString(36).substr(2, 9);
    const y = -100; // Spawn above screen

    if (type === ObstacleType.GAP_WALL) {
       // A wall with a gap
       const gapWidth = laneWidth * 1.5;
       const gapX = Math.random() * (width - gapWidth);

       // Left part
       obstaclesRef.current.push({
         id: `${id}-1`, x: 0, y, width: gapX, height: 40, 
         speed: 0, type, passed: false
       });
       // Right part
       obstaclesRef.current.push({
         id: `${id}-2`, x: gapX + gapWidth, y, width: width - (gapX + gapWidth), height: 40, 
         speed: 0, type, passed: false
       });
    } else if (type === ObstacleType.MOVING_BLOCK) {
      const w = laneWidth * 0.8;
      const x = Math.random() * (width - w);
      obstaclesRef.current.push({
        id, x, y, width: w, height: 40, 
        speed: 2 + Math.random() * 2, type, passed: false,
        direction: Math.random() > 0.5 ? 1 : -1
      });
    } else {
      // Standard Blocks
      const count = Math.floor(Math.random() * 2) + 1; // 1 or 2 blocks
      for(let i=0; i<count; i++) {
         const w = laneWidth * 0.8;
         // Quantize to lanes for easier gameplay
         const lane = Math.floor(Math.random() * GAME_CONFIG.LANE_COUNT);
         const x = (lane * laneWidth) + (laneWidth - w)/2;

         // Avoid overlapping exactly
         if (!obstaclesRef.current.some(o => Math.abs(o.y - y) < 10 && Math.abs(o.x - x) < 10)) {
            obstaclesRef.current.push({
              id: `${id}-${i}`, x, y, width: w, height: 40 + Math.random() * 40, 
              speed: 0, type, passed: false
            });
         }
      }
    }

    // Chance to spawn powerup
    if (Math.random() < 0.1) {
       const pX = Math.random() * (width - 40) + 20;
       const rand = Math.random();
       let pType = PowerUpType.SCORE_BOOST;

       if (rand > 0.75) {
         pType = PowerUpType.SHIELD;
       } else if (rand > 0.5) {
         pType = PowerUpType.SCORE_MULTIPLIER;
       }

       powerUpsRef.current.push({
         id: Math.random().toString(),
         x: pX, y: y - 100, radius: 15,
         type: pType, active: true
       });
    }
  };

  const createParticles = (x: number, y: number, color: string, count: number) => {
    for (let i = 0; i < count; i++) {
      particlesRef.current.push({
        x, y,
        vx: (Math.random() - 0.5) * 10,
        vy: (Math.random() - 0.5) * 10,
        life: 1.0,
        color,
        size: Math.random() * 4 + 2
      });
    }
  };

  const checkCollision = (rect: Obstacle, circle: Player) => {
    // Closest point on rectangle to circle center
    const clampX = Math.max(rect.x, Math.min(circle.x, rect.x + rect.width));
    const clampY = Math.max(rect.y, Math.min(circle.y, rect.y + rect.height));

    const dx = circle.x - clampX;
    const dy = circle.y - clampY;

    return (dx * dx + dy * dy) < (circle.radius * circle.radius);
  };

  const checkCircleCollision = (p1: {x: number, y: number, radius: number}, p2: {x: number, y: number, radius: number}) => {
     const dx = p1.x - p2.x;
     const dy = p1.y - p2.y;
     const dist = Math.sqrt(dx*dx + dy*dy);
     return dist < (p1.radius + p2.radius);
  };

  // --- Main Loop ---

  const update = (deltaTime: number, frameCount: number) => {
    if (!canvasRef.current) return;
    const canvas = canvasRef.current;
    const width = canvas.width;
    const height = canvas.height;

    // Increase difficulty
    scrollSpeedRef.current = Math.min(
      GAME_CONFIG.MAX_SCROLL_SPEED, 
      scrollSpeedRef.current + GAME_CONFIG.SPEED_INCREMENT
    );

    // Score Calculation with Multiplier
    scoreRef.current += (scrollSpeedRef.current / 10) * scoreMultiplierRef.current;
    setScore(scoreRef.current); 

    // Check Multiplier Expiration
    if (scoreMultiplierRef.current > 1 && frameCount > multiplierEndFrameRef.current) {
       scoreMultiplierRef.current = 1;
       setScoreMultiplier(1);
    }

    // Update Player Movement
    let dx = 0;
    if (keysPressed.current['ArrowLeft'] || keysPressed.current['a'] || keysPressed.current['A']) dx -= 1;
    if (keysPressed.current['ArrowRight'] || keysPressed.current['d'] || keysPressed.current['D']) dx += 1;

    // Touch Logic
    if (touchX.current !== null) {
       const diff = touchX.current - playerRef.current.x;
       if (Math.abs(diff) > 5) {
          dx = Math.sign(diff);
       }
    }

    // Apply Physics
    playerRef.current.x += dx * playerRef.current.speed;

    // Boundary Checks
    if (playerRef.current.x < playerRef.current.radius) playerRef.current.x = playerRef.current.radius;
    if (playerRef.current.x > width - playerRef.current.radius) playerRef.current.x = width - playerRef.current.radius;

    // Trail Effect
    if (frameCount % 5 === 0) {
      playerRef.current.trail.push({ x: playerRef.current.x, y: playerRef.current.y });
      if (playerRef.current.trail.length > 10) playerRef.current.trail.shift();
    }

    // Update Obstacles
    // Spawn logic based on distance traveled (simulated by frames/speed here)
    if (frameCount % Math.floor(GAME_CONFIG.OBSTACLE_SPAWN_RATE * (5 / scrollSpeedRef.current)) === 0) {
      spawnObstacle(width);
    }

    // Move & Filter Obstacles
    for (let i = obstaclesRef.current.length - 1; i >= 0; i--) {
      const obs = obstaclesRef.current[i];
      obs.y += scrollSpeedRef.current;

      // Horizontal movement for moving blocks
      if (obs.type === ObstacleType.MOVING_BLOCK && obs.direction) {
        obs.x += obs.speed * obs.direction;
        if (obs.x <= 0 || obs.x + obs.width >= width) {
          obs.direction *= -1;
        }
      }

      // Collision Check
      if (checkCollision(obs, playerRef.current)) {
         if (playerRef.current.shieldActive) {
            playerRef.current.shieldActive = false;
            setHasShield(false);
            createParticles(obs.x + obs.width/2, obs.y + obs.height/2, GAME_CONFIG.COLORS.OBSTACLE, 20);
            obstaclesRef.current.splice(i, 1); // Destroy obstacle
            continue;
         } else {
            setGameState(GameState.GAME_OVER);
            createParticles(playerRef.current.x, playerRef.current.y, GAME_CONFIG.COLORS.PLAYER, 50);
            return; // Stop update loop
         }
      }

      // Cleanup off-screen
      if (obs.y > height) {
        obstaclesRef.current.splice(i, 1);
      }
    }

    // Update PowerUps
    for (let i = powerUpsRef.current.length - 1; i >= 0; i--) {
      const p = powerUpsRef.current[i];
      p.y += scrollSpeedRef.current;

      if (checkCircleCollision(playerRef.current, p)) {
        if (p.type === PowerUpType.SHIELD) {
          playerRef.current.shieldActive = true;
          setHasShield(true);
        } else if (p.type === PowerUpType.SCORE_BOOST) {
          scoreRef.current += 500 * scoreMultiplierRef.current;
          createParticles(p.x, p.y, GAME_CONFIG.COLORS.POWERUP_SCORE, 10);
        } else if (p.type === PowerUpType.SCORE_MULTIPLIER) {
          scoreMultiplierRef.current = 2; // Double Score
          multiplierEndFrameRef.current = frameCount + 600; // ~10 Seconds at 60FPS
          setScoreMultiplier(2);
          createParticles(p.x, p.y, GAME_CONFIG.COLORS.POWERUP_MULTIPLIER, 20);
        }
        powerUpsRef.current.splice(i, 1);
      } else if (p.y > height) {
        powerUpsRef.current.splice(i, 1);
      }
    }

    // Update Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
       const p = particlesRef.current[i];
       p.x += p.vx;
       p.y += p.vy;
       p.life -= 0.02;
       if (p.life <= 0) particlesRef.current.splice(i, 1);
    }
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const width = canvas.width;
    const height = canvas.height;

    // Clear
    ctx.fillStyle = GAME_CONFIG.COLORS.BACKGROUND_GRID;
    ctx.fillRect(0, 0, width, height);

    // Draw Moving Grid (Perspective illusion)
    ctx.strokeStyle = 'rgba(6, 182, 212, 0.1)';
    ctx.lineWidth = 1;
    const gridOffset = (Date.now() / 10 * scrollSpeedRef.current) % 100;

    // Vertical lines
    for (let i = 0; i <= GAME_CONFIG.LANE_COUNT; i++) {
        const x = (width / GAME_CONFIG.LANE_COUNT) * i;
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
        ctx.stroke();
    }

    // Horizontal moving lines
    for (let y = gridOffset - 100; y < height; y += 100) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
    }

    // Draw Particles
    particlesRef.current.forEach(p => {
       ctx.globalAlpha = p.life;
       ctx.fillStyle = p.color;
       ctx.beginPath();
       ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
       ctx.fill();
       ctx.globalAlpha = 1.0;
    });

    // Draw PowerUps
    powerUpsRef.current.forEach(p => {
       let color = GAME_CONFIG.COLORS.POWERUP_SCORE;
       let symbol = '+';
       if (p.type === PowerUpType.SHIELD) {
          color = GAME_CONFIG.COLORS.POWERUP_SHIELD;
          symbol = 'S';
       } else if (p.type === PowerUpType.SCORE_MULTIPLIER) {
          color = GAME_CONFIG.COLORS.POWERUP_MULTIPLIER;
          symbol = 'x2';
       }

       ctx.shadowBlur = 15;
       ctx.shadowColor = color;
       ctx.fillStyle = color;
       ctx.beginPath();
       ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
       ctx.fill();

       // Inner Icon
       ctx.fillStyle = '#fff';
       ctx.font = 'bold 12px Arial';
       ctx.textAlign = 'center';
       ctx.textBaseline = 'middle';
       ctx.fillText(symbol, p.x, p.y);
       ctx.shadowBlur = 0;
    });

    // Draw Obstacles
    obstaclesRef.current.forEach(obs => {
      ctx.shadowBlur = 10;
      ctx.shadowColor = GAME_CONFIG.COLORS.OBSTACLE_GLOW;
      ctx.fillStyle = GAME_CONFIG.COLORS.OBSTACLE;

      // Rounded rects
      ctx.beginPath();
      ctx.roundRect(obs.x, obs.y, obs.width, obs.height, 4);
      ctx.fill();
      ctx.shadowBlur = 0;

      // Detail line
      ctx.fillStyle = 'rgba(255,255,255,0.2)';
      ctx.fillRect(obs.x, obs.y + 5, obs.width, 5);
    });

    // Draw Player Trail
    const player = playerRef.current;
    if (player.trail.length > 1) {
       ctx.beginPath();
       ctx.moveTo(player.trail[0].x, player.trail[0].y);
       for (let i = 1; i < player.trail.length; i++) {
         ctx.lineTo(player.trail[i].x, player.trail[i].y);
       }
       ctx.strokeStyle = `rgba(6, 182, 212, 0.3)`;
       ctx.lineWidth = player.radius;
       ctx.lineCap = 'round';
       ctx.stroke();
    }

    // Draw Player
    ctx.shadowBlur = 20;
    ctx.shadowColor = player.shieldActive ? GAME_CONFIG.COLORS.PLAYER_SHIELD : GAME_CONFIG.COLORS.PLAYER;
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.arc(player.x, player.y, player.radius, 0, Math.PI * 2);
    ctx.fill();

    // Shield glow ring
    if (player.shieldActive) {
       ctx.strokeStyle = GAME_CONFIG.COLORS.PLAYER_SHIELD;
       ctx.lineWidth = 2;
       ctx.beginPath();
       ctx.arc(player.x, player.y, player.radius + 5, 0, Math.PI * 2);
       ctx.stroke();
    }

    ctx.shadowBlur = 0;
  };

  const gameLoop = (time: number) => {
    if (gameState === GameState.PLAYING) {
       const deltaTime = time - lastTimeRef.current;
       lastTimeRef.current = time;
       update(deltaTime, Math.floor(time / 16)); // Pass rough frame count
    }
    draw();
    requestRef.current = requestAnimationFrame(gameLoop);
  };

  // --- Effects ---

  useEffect(() => {
    // Input Listeners
    const handleKeyDown = (e: KeyboardEvent) => keysPressed.current[e.key] = true;
    const handleKeyUp = (e: KeyboardEvent) => keysPressed.current[e.key] = false;

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    // Initial Render
    initGame();
    requestRef.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run once on mount

  // Watch for Game Reset
  useEffect(() => {
     if (gameState === GameState.PLAYING && scoreRef.current === 0) {
        initGame();
     }
  }, [gameState, initGame]);

  // Handle Touch
  const handleTouchStart = (e: React.TouchEvent) => {
    touchX.current = e.touches[0].clientX;
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    touchX.current = e.touches[0].clientX;
    // Prevent scrolling logic handled by CSS touch-action: none
  };

  const handleTouchEnd = () => {
    touchX.current = null;
  };

  return (
    <div ref={containerRef} className="absolute inset-0 w-full h-full bg-slate-900">
      <canvas
        ref={canvasRef}
        className="block w-full h-full touch-none"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
      />
    </div>
  );
};

