                  <Move size={18} />
                  <span className="text-xs font-bold uppercase">Tilt</span>
               </button>
            </div>

            <button
              onClick={onStart}
              className="group relative w-full px-8 py-5 bg-cyan-600 hover:bg-cyan-500 text-white font-bold rounded-xl transition-all duration-200 shadow-[0_0_20px_rgba(6,182,212,0.5)] hover:shadow-[0_0_30px_rgba(6,182,212,0.7)] overflow-hidden active:scale-95"
            >
              <div className="absolute inset-0 w-full h-full bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:animate-[shimmer_1s_infinite]"></div>
              <div className="flex items-center justify-center gap-3">
                <Play size={24} fill="currentColor" />
                <span className="text-lg tracking-widest score-font">PLAY NOW</span>
              </div>
            </button>
          </div>
