        {gameState === GameState.GAME_OVER && (
          <div className="bg-slate-900/95 backdrop-blur-xl p-8 rounded-2xl border-2 border-rose-500/50 shadow-[0_0_50px_rgba(244,63,94,0.3)] text-center max-w-sm w-full animate-in zoom-in-95 duration-300 mx-4">
            <h2 className="text-4xl font-black text-rose-500 mb-2 score-font tracking-tighter">FAILURE</h2>
            <div className="py-6 space-y-2">
              <p className="text-slate-400 text-sm uppercase tracking-widest">Final Score</p>
              <p className="text-5xl font-black text-white score-font">{Math.floor(score).toLocaleString()}</p>
            </div>
            <button
              onClick={onRestart}
              className="w-full px-8 py-5 bg-rose-600 hover:bg-rose-500 text-white font-bold rounded-xl transition-all duration-200 shadow-[0_0_20px_rgba(244,63,94,0.5)] hover:shadow-[0_0_30px_rgba(244,63,94,0.7)] flex items-center justify-center gap-3 active:scale-95"
            >
              <RotateCcw size={24} />
              <span className="text-lg tracking-widest score-font">RETRY</span>
            </button>
          </div>
        )}
      </div>

      {/* Controls Hint */}
      {gameState === GameState.PLAYING && (
        <div className="absolute bottom-12 left-0 right-0 flex justify-center opacity-30 pointer-events-none">
             {controlMode === ControlMode.TOUCH ? (
               <div className="flex justify-between w-full px-12">
                   <div className="flex flex-col items-center animate-pulse">
                      <div className="w-16 h-16 rounded-full border-2 border-white flex items-center justify-center bg-white/10">
                         <span className="text-2xl font-bold text-white">&lt;</span>
                      </div>
                   </div>
                   <div className="flex flex-col items-center animate-pulse">
                      <div className="w-16 h-16 rounded-full border-2 border-white flex items-center justify-center bg-white/10">
                         <span className="text-2xl font-bold text-white">&gt;</span>
                      </div>
                   </div>
               </div>
             ) : (
                <div className="flex items-center gap-3 animate-pulse bg-slate-900/50 px-4 py-2 rounded-full border border-white/20">
                    <Move className="text-white" size={20} />
                    <span className="text-white text-sm font-bold uppercase tracking-wider">Tilt Device</span>
                </div>
             )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { GameCanvas } from './components/GameCanvas';
import { GameOverlay } from './components/GameOverlay';
import { GameState, ControlMode } from './types';

export default function App() {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [hasShield, setHasShield] = useState(false);
  const [scoreMultiplier, setScoreMultiplier] = useState(1);
  const [controlMode, setControlMode] = useState<ControlMode>(ControlMode.TOUCH);

  // Load High Score
  useEffect(() => {
    const saved = localStorage.getItem('neon_escape_highscore');
    if (saved) setHighScore(parseInt(saved, 10));
  }, []);

  // Update High Score
  useEffect(() => {
    if (score > highScore) {
      setHighScore(Math.floor(score));
      localStorage.setItem('neon_escape_highscore', Math.floor(score).toString());
    }
  }, [score, highScore]);

  const handleStart = () => {
    setScore(0);
    setScoreMultiplier(1);
    setGameState(GameState.PLAYING);
  };

  const handleRestart = () => {
    setScore(0);
    setScoreMultiplier(1);
    setGameState(GameState.PLAYING);
  };

  return (
    <div className="relative w-full h-screen overflow-hidden bg-slate-950">
      <GameCanvas 
        gameState={gameState} 
        setGameState={setGameState}
        score={score}
        setScore={setScore}
        setHasShield={setHasShield}
        setScoreMultiplier={setScoreMultiplier}
        controlMode={controlMode}
      />
      <GameOverlay 
        gameState={gameState} 
        score={score}
        highScore={highScore}
        onStart={handleStart}
        onRestart={handleRestart}
        hasShield={hasShield}
        scoreMultiplier={scoreMultiplier}
        controlMode={controlMode}
        setControlMode={setControlMode}
      />
    </div>
  );
}

