import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, Obstacle, ObstacleType, Particle, Player, Point, PowerUp, PowerUpType, ControlMode } from '../types';
import { GAME_CONFIG } from '../constants';

interface GameCanvasProps {
  setGameState: (state: GameState) => void;
  gameState: GameState;
  score: number;
  setScore: (score: number) => void;
  setHasShield: (hasShield: boolean) => void;
  setScoreMultiplier: (multiplier: number) => void;
  controlMode: ControlMode;
  setItemsCollected: (count: number) => void;
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ 
  gameState, 
  setGameState, 
  score, 
  setScore,
  setHasShield,
  setScoreMultiplier,
  controlMode,
  setItemsCollected
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Game Loop Refs
  const requestRef = useRef<number>();
  const lastTimeRef = useRef<number>(0);
  const scrollSpeedRef = useRef<number>(GAME_CONFIG.INITIAL_SCROLL_SPEED);
  const scoreRef = useRef<number>(0);
  const itemsCollectedRef = useRef<number>(0);
  const scoreMultiplierRef = useRef<number>(1);
  const multiplierEndFrameRef = useRef<number>(0);
  const shakeRef = useRef<number>(0);

  // Entities
  const playerRef = useRef<Player>({
    x: 0, 
    y: 0, 
    radius: GAME_CONFIG.PLAYER_RADIUS, 
    velocity: { x: 0, y: 0 }, 
    speed: GAME_CONFIG.PLAYER_SPEED,
    color: GAME_CONFIG.COLORS.PLAYER,
    shieldActive: false,
    trail: []
  });

  const obstaclesRef = useRef<Obstacle[]>([]);
  const powerUpsRef = useRef<PowerUp[]>([]);
  const particlesRef = useRef<Particle[]>([]);

  // Input State
  const keysPressed = useRef<{ [key: string]: boolean }>({});
  const touchX = useRef<number | null>(null);
  const tiltGamma = useRef<number>(0);

  // --- Initialization ---

  const initGame = useCallback(() => {
    if (!containerRef.current || !canvasRef.current) return;

    const { width, height } = containerRef.current.getBoundingClientRect();
    canvasRef.current.width = width;
    canvasRef.current.height = height;

    playerRef.current = {
      x: width / 2,
      y: height - 150,
      radius: GAME_CONFIG.PLAYER_RADIUS,
      velocity: { x: 0, y: 0 },
      speed: GAME_CONFIG.PLAYER_SPEED,
      color: GAME_CONFIG.COLORS.PLAYER,
      shieldActive: false,
      trail: []
    };

    obstaclesRef.current = [];
    powerUpsRef.current = [];
    particlesRef.current = [];
    scrollSpeedRef.current = GAME_CONFIG.INITIAL_SCROLL_SPEED;
    scoreRef.current = 0;
    itemsCollectedRef.current = 0;
    scoreMultiplierRef.current = 1;
    multiplierEndFrameRef.current = 0;
    shakeRef.current = 0;

    setScore(0);
    setItemsCollected(0);
    setHasShield(false);
    setScoreMultiplier(1);
  }, [setScore, setItemsCollected, setHasShield, setScoreMultiplier]);

  // --- Helper Functions ---

  const spawnObstacle = (width: number) => {
    const laneWidth = width / GAME_CONFIG.LANE_COUNT;
    const typeRoll = Math.random();
    let type = ObstacleType.BLOCK;
    if (scoreRef.current > 500 && typeRoll > 0.7) type = ObstacleType.MOVING_BLOCK;
    if (scoreRef.current > 1000 && typeRoll > 0.9) type = ObstacleType.GAP_WALL;

    const id = Math.random().toString(36).substr(2, 9);
    const y = -100;

    if (type === ObstacleType.GAP_WALL) {
       const gapWidth = laneWidth * 1.5;
       const gapX = Math.random() * (width - gapWidth);
       obstaclesRef.current.push({
         id: `${id}-1`, x: 0, y, width: gapX, height: 40, 
         speed: 0, type, passed: false
       });
       obstaclesRef.current.push({
         id: `${id}-2`, x: gapX + gapWidth, y, width: width - (gapX + gapWidth), height: 40, 
         speed: 0, type, passed: false
       });
    } else if (type === ObstacleType.MOVING_BLOCK) {
      const w = laneWidth * 0.8;
      const x = Math.random() * (width - w);
      obstaclesRef.current.push({
        id, x, y, width: w, height: 40, 
        speed: 2 + Math.random() * 2, type, passed: false,
        direction: Math.random() > 0.5 ? 1 : -1
      });
    } else {
      const count = Math.floor(Math.random() * 2) + 1;
      for(let i=0; i<count; i++) {
         const w = laneWidth * 0.8;
         const lane = Math.floor(Math.random() * GAME_CONFIG.LANE_COUNT);
         const x = (lane * laneWidth) + (laneWidth - w)/2;
         if (!obstaclesRef.current.some(o => Math.abs(o.y - y) < 10 && Math.abs(o.x - x) < 10)) {
            obstaclesRef.current.push({
              id: `${id}-${i}`, x, y, width: w, height: 40 + Math.random() * 40, 
              speed: 0, type, passed: false
            });
         }
      }
    }

    if (Math.random() < 0.1) {
       const pX = Math.random() * (width - 40) + 20;
       const rand = Math.random();
       let pType = PowerUpType.SCORE_BOOST;

       if (rand > 0.75) pType = PowerUpType.SHIELD;
       else if (rand > 0.5) pType = PowerUpType.SCORE_MULTIPLIER;

       powerUpsRef.current.push({
         id: Math.random().toString(),
         x: pX, y: y - 100, radius: 15,
         type: pType, active: true
       });
    }
  };

  const createBurst = (x: number, y: number, color: string, count: number) => {
    for (let i = 0; i < count; i++) {
      const angle = Math.random() * Math.PI * 2;
      const speed = Math.random() * 6 + 2;
      particlesRef.current.push({
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1.0,
        color,
        size: Math.random() * 3 + 2
      });
    }
  };

  const createParticles = (x: number, y: number, color: string, count: number) => {
      createBurst(x, y, color, count);
  };

  const checkCollision = (rect: Obstacle, circle: Player) => {
    const clampX = Math.max(rect.x, Math.min(circle.x, rect.x + rect.width));
    const clampY = Math.max(rect.y, Math.min(circle.y, rect.y + rect.height));
    const dx = circle.x - clampX;
    const dy = circle.y - clampY;
    return (dx * dx + dy * dy) < (circle.radius * circle.radius);
  };

  const checkCircleCollision = (p1: {x: number, y: number, radius: number}, p2: {x: number, y: number, radius: number}) => {
     const dx = p1.x - p2.x;
     const dy = p1.y - p2.y;
     const dist = Math.sqrt(dx*dx + dy*dy);
     return dist < (p1.radius + p2.radius);
  };

  // --- Main Loop ---

  const update = (deltaTime: number, frameCount: number) => {
    if (!canvasRef.current) return;
    const canvas = canvasRef.current;
    const width = canvas.width;
    const height = canvas.height;

    // Shake Decay
    if (shakeRef.current > 0) {
      shakeRef.current = Math.max(0, shakeRef.current - 1);
    }

    scrollSpeedRef.current = Math.min(
      GAME_CONFIG.MAX_SCROLL_SPEED, 
      scrollSpeedRef.current + GAME_CONFIG.SPEED_INCREMENT
    );

    scoreRef.current += (scrollSpeedRef.current / 10) * scoreMultiplierRef.current;
    setScore(scoreRef.current); 

    if (scoreMultiplierRef.current > 1 && frameCount > multiplierEndFrameRef.current) {
       scoreMultiplierRef.current = 1;
       setScoreMultiplier(1);
    }

    // --- Control Logic ---
    let dx = 0;

    // 1. Keyboard
    if (keysPressed.current['ArrowLeft'] || keysPressed.current['a'] || keysPressed.current['A']) dx -= 1;
    if (keysPressed.current['ArrowRight'] || keysPressed.current['d'] || keysPressed.current['D']) dx += 1;

    // 2. Mobile Controls
    if (controlMode === ControlMode.TILT) {
      const deadzone = 2;
      const sensitivity = 0.05;
      let val = tiltGamma.current;
      if (Math.abs(val) > deadzone) {
         dx += val * sensitivity; 
      }
    } else {
      // Touch Logic
      if (touchX.current !== null) {
         const diff = touchX.current - playerRef.current.x;
         const threshold = 10;
         if (Math.abs(diff) > threshold) {
            dx += Math.sign(diff); 
         }
      }
    }

    if (controlMode !== ControlMode.TILT) {
        dx = Math.max(-1, Math.min(1, dx));
    } else {
        dx = Math.max(-2, Math.min(2, dx)); 
    }

    playerRef.current.x += dx * playerRef.current.speed;

    // Boundary Checks
    if (playerRef.current.x < playerRef.current.radius) playerRef.current.x = playerRef.current.radius;
    if (playerRef.current.x > width - playerRef.current.radius) playerRef.current.x = width - playerRef.current.radius;

    // Enhanced Trail: Push every frame, keep last 20
    playerRef.current.trail.push({ x: playerRef.current.x, y: playerRef.current.y });
    if (playerRef.current.trail.length > 20) playerRef.current.trail.shift();

    // Spawn
    if (frameCount % Math.floor(GAME_CONFIG.OBSTACLE_SPAWN_RATE * (5 / scrollSpeedRef.current)) === 0) {
      spawnObstacle(width);
    }

    // Obstacles
    for (let i = obstaclesRef.current.length - 1; i >= 0; i--) {
      const obs = obstaclesRef.current[i];
      obs.y += scrollSpeedRef.current;

      if (obs.type === ObstacleType.MOVING_BLOCK && obs.direction) {
        obs.x += obs.speed * obs.direction;
        if (obs.x <= 0 || obs.x + obs.width >= width) {
          obs.direction *= -1;
        }
      }

      if (checkCollision(obs, playerRef.current)) {
         if (playerRef.current.shieldActive) {
            playerRef.current.shieldActive = false;
            setHasShield(false);
            createBurst(obs.x + obs.width/2, obs.y + obs.height/2, GAME_CONFIG.COLORS.OBSTACLE, 20);
            obstaclesRef.current.splice(i, 1);
            continue;
         } else {
            shakeRef.current = 20; // Trigger Screen Shake
            setGameState(GameState.GAME_OVER);
            createBurst(playerRef.current.x, playerRef.current.y, GAME_CONFIG.COLORS.PLAYER, 50);
            return;
         }
      }
      if (obs.y > height) obstaclesRef.current.splice(i, 1);
    }

    // PowerUps
    for (let i = powerUpsRef.current.length - 1; i >= 0; i--) {
      const p = powerUpsRef.current[i];
      p.y += scrollSpeedRef.current;

      if (checkCircleCollision(playerRef.current, p)) {
        itemsCollectedRef.current++;
        setItemsCollected(itemsCollectedRef.current);

        let burstColor = GAME_CONFIG.COLORS.POWERUP_SCORE;
        if (p.type === PowerUpType.SHIELD) {
          playerRef.current.shieldActive = true;
          setHasShield(true);
          burstColor = GAME_CONFIG.COLORS.POWERUP_SHIELD;
        } else if (p.type === PowerUpType.SCORE_BOOST) {
          scoreRef.current += 500 * scoreMultiplierRef.current;
          burstColor = GAME_CONFIG.COLORS.POWERUP_SCORE;
        } else if (p.type === PowerUpType.SCORE_MULTIPLIER) {
          scoreMultiplierRef.current = 2;
          multiplierEndFrameRef.current = frameCount + 600;
          setScoreMultiplier(2);
          burstColor = GAME_CONFIG.COLORS.POWERUP_MULTIPLIER;
        }

        createBurst(p.x, p.y, burstColor, 30);
        powerUpsRef.current.splice(i, 1);
      } else if (p.y > height) {
        powerUpsRef.current.splice(i, 1);
      }
    }

    // Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
       const p = particlesRef.current[i];
       p.x += p.vx;
       p.y += p.vy;
       p.life -= 0.03; // Faster fade for bursts
       if (p.life <= 0) particlesRef.current.splice(i, 1);
    }
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const width = canvas.width;
    const height = canvas.height;

    ctx.save(); // Save before shake

    // Apply Shake
    if (shakeRef.current > 0) {
       const dx = (Math.random() - 0.5) * shakeRef.current * 2;
       const dy = (Math.random() - 0.5) * shakeRef.current * 2;
       ctx.translate(dx, dy);
    }

    // Background
    ctx.fillStyle = GAME_CONFIG.COLORS.BACKGROUND_GRID;
    ctx.fillRect(-20, -20, width + 40, height + 40); // Oversize to cover shake edges

    // Grid
    ctx.strokeStyle = 'rgba(6, 182, 212, 0.1)';
    ctx.lineWidth = 1;
    const gridOffset = (Date.now() / 10 * scrollSpeedRef.current) % 100;

    for (let i = 0; i <= GAME_CONFIG.LANE_COUNT; i++) {
        const x = (width / GAME_CONFIG.LANE_COUNT) * i;
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
        ctx.stroke();
    }
    for (let y = gridOffset - 100; y < height; y += 100) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
    }

    // Particles
    particlesRef.current.forEach(p => {
       ctx.globalAlpha = p.life;
       ctx.fillStyle = p.color;
       ctx.beginPath();
       ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
       ctx.fill();
       ctx.globalAlpha = 1.0;
    });

    // PowerUps
    powerUpsRef.current.forEach(p => {
       let color = GAME_CONFIG.COLORS.POWERUP_SCORE;
       let symbol = '+';
       if (p.type === PowerUpType.SHIELD) {
          color = GAME_CONFIG.COLORS.POWERUP_SHIELD;
          symbol = 'S';
       } else if (p.type === PowerUpType.SCORE_MULTIPLIER) {
          color = GAME_CONFIG.COLORS.POWERUP_MULTIPLIER;
          symbol = 'x2';
       }

       ctx.shadowBlur = 15;
       ctx.shadowColor = color;
       ctx.fillStyle = color;
       ctx.beginPath();
       ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
       ctx.fill();

       ctx.fillStyle = '#fff';
       ctx.font = 'bold 12px Arial';
       ctx.textAlign = 'center';
       ctx.textBaseline = 'middle';
       ctx.fillText(symbol, p.x, p.y);
       ctx.shadowBlur = 0;
    });

    // Obstacles
    obstaclesRef.current.forEach(obs => {
      ctx.shadowBlur = 10;
      ctx.shadowColor = GAME_CONFIG.COLORS.OBSTACLE_GLOW;
      ctx.fillStyle = GAME_CONFIG.COLORS.OBSTACLE;
      ctx.beginPath();
      ctx.roundRect(obs.x, obs.y, obs.width, obs.height, 4);
      ctx.fill();
      ctx.shadowBlur = 0;
      ctx.fillStyle = 'rgba(255,255,255,0.2)';
      ctx.fillRect(obs.x, obs.y + 5, obs.width, 5);
    });

    // Trail (Enhanced)
    const player = playerRef.current;
    if (player.trail.length > 1) {
       for (let i = 0; i < player.trail.length - 1; i++) {
         const p1 = player.trail[i];
         const p2 = player.trail[i+1];
         const ratio = i / player.trail.length;

         ctx.beginPath();
         ctx.moveTo(p1.x, p1.y);
         ctx.lineTo(p2.x, p2.y);
         ctx.lineCap = 'round';
         ctx.strokeStyle = player.color;
         ctx.lineWidth = player.radius * 2 * ratio; // Tapering
         ctx.globalAlpha = ratio * 0.5; // Fading
         ctx.stroke();
       }
       ctx.globalAlpha = 1.0;
    }

    // Player
    ctx.shadowBlur = 20;
    ctx.shadowColor = player.shieldActive ? GAME_CONFIG.COLORS.PLAYER_SHIELD : GAME_CONFIG.COLORS.PLAYER;
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.arc(player.x, player.y, player.radius, 0, Math.PI * 2);
    ctx.fill();

    if (player.shieldActive) {
       ctx.strokeStyle = GAME_CONFIG.COLORS.PLAYER_SHIELD;
       ctx.lineWidth = 2;
       ctx.beginPath();
       ctx.arc(player.x, player.y, player.radius + 5, 0, Math.PI * 2);
       ctx.stroke();
    }

    ctx.shadowBlur = 0;

    ctx.restore(); // Restore context after shake
  };

  const gameLoop = (time: number) => {
    if (gameState === GameState.PLAYING) {
       const deltaTime = time - lastTimeRef.current;
       lastTimeRef.current = time;
       update(deltaTime, Math.floor(time / 16)); 
    }
    draw();
    requestRef.current = requestAnimationFrame(gameLoop);
  };

  // --- Effects ---

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => keysPressed.current[e.key] = true;
    const handleKeyUp = (e: KeyboardEvent) => keysPressed.current[e.key] = false;

    const handleOrientation = (e: DeviceOrientationEvent) => {
      if (e.gamma !== null) tiltGamma.current = e.gamma;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('deviceorientation', handleOrientation);

    initGame();
    requestRef.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('deviceorientation', handleOrientation);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [initGame]); 

  useEffect(() => {
     if (gameState === GameState.PLAYING && scoreRef.current === 0) {
        initGame();
     }
  }, [gameState, initGame]);

  const handleTouchStart = (e: React.TouchEvent) => {
    touchX.current = e.touches[0].clientX;
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    touchX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = () => {
    touchX.current = null;
  };

  return (
    <div ref={containerRef} className="absolute inset-0 w-full h-full bg-slate-900">
      <canvas
        ref={canvasRef}
        className="block w-full h-full touch-none"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
      />
    </div>
  );
};

export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
}

export enum ControlMode {
  TOUCH = 'TOUCH',
  TILT = 'TILT',
}

export interface Point {
  x: number;
  y: number;
  width?: number; // Optional for non-point usage
  height?: number;
}

export interface Player {
  x: number;
  y: number;
  radius: number;
  velocity: Point;
  speed: number;
  color: string;
  shieldActive: boolean;
  trail: Point[];
}

export enum ObstacleType {
  BLOCK = 'BLOCK',
  MOVING_BLOCK = 'MOVING_BLOCK',
  GAP_WALL = 'GAP_WALL',
  ROTATING_SPIKE = 'ROTATING_SPIKE',
  LASER_BEAM = 'LASER_BEAM',
}

export interface Obstacle {
  id: string;
  x: number;
  y: number;
  width: number;
  height: number;
  speed: number;
  type: ObstacleType;
  passed: boolean; // Has the player passed this obstacle?
  direction?: number; // For moving blocks: 1 or -1
  rotation?: number; // For rotating spikes
  laserState?: 'WARNING' | 'ACTIVE' | 'COOLDOWN'; // For lasers
  laserTimer?: number;
}

export enum PowerUpType {
  SHIELD = 'SHIELD',
  SCORE_BOOST = 'SCORE_BOOST',
  SCORE_MULTIPLIER = 'SCORE_MULTIPLIER',
}

export interface PowerUp {
  id: string;
  x: number;
  y: number;
  radius: number;
  type: PowerUpType;
  active: boolean;
}

export interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;
  color: string;
  size: number;
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GameState, Obstacle, ObstacleType, Particle, Player, Point, PowerUp, PowerUpType, ControlMode } from '../types';
import { GAME_CONFIG } from '../constants';

interface GameCanvasProps {
  setGameState: (state: GameState) => void;
  gameState: GameState;
  score: number;
  setScore: (score: number) => void;
  setHasShield: (hasShield: boolean) => void;
  setScoreMultiplier: (multiplier: number) => void;
  controlMode: ControlMode;
  setItemsCollected: (count: number) => void;
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ 
  gameState, 
  setGameState, 
  score, 
  setScore,
  setHasShield,
  setScoreMultiplier,
  controlMode,
  setItemsCollected
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Game Loop Refs
  const requestRef = useRef<number>();
  const lastTimeRef = useRef<number>(0);
  const scrollSpeedRef = useRef<number>(GAME_CONFIG.INITIAL_SCROLL_SPEED);
  const scoreRef = useRef<number>(0);
  const itemsCollectedRef = useRef<number>(0);
  const scoreMultiplierRef = useRef<number>(1);
  const multiplierEndFrameRef = useRef<number>(0);
  const shakeRef = useRef<number>(0);

  // Entities
  const playerRef = useRef<Player>({
    x: 0, 
    y: 0, 
    radius: GAME_CONFIG.PLAYER_RADIUS, 
    velocity: { x: 0, y: 0 }, 
    speed: GAME_CONFIG.PLAYER_SPEED,
    color: GAME_CONFIG.COLORS.PLAYER,
    shieldActive: false,
    trail: []
  });

  const obstaclesRef = useRef<Obstacle[]>([]);
  const powerUpsRef = useRef<PowerUp[]>([]);
  const particlesRef = useRef<Particle[]>([]);

  // Input State
  const keysPressed = useRef<{ [key: string]: boolean }>({});
  const touchX = useRef<number | null>(null);
  const tiltGamma = useRef<number>(0);

  // --- Initialization ---

  const initGame = useCallback(() => {
    if (!containerRef.current || !canvasRef.current) return;

    const { width, height } = containerRef.current.getBoundingClientRect();
    canvasRef.current.width = width;
    canvasRef.current.height = height;

    playerRef.current = {
      x: width / 2,
      y: height - 150,
      radius: GAME_CONFIG.PLAYER_RADIUS,
      velocity: { x: 0, y: 0 },
      speed: GAME_CONFIG.PLAYER_SPEED,
      color: GAME_CONFIG.COLORS.PLAYER,
      shieldActive: false,
      trail: []
    };

    obstaclesRef.current = [];
    powerUpsRef.current = [];
    particlesRef.current = [];
    scrollSpeedRef.current = GAME_CONFIG.INITIAL_SCROLL_SPEED;
    scoreRef.current = 0;
    itemsCollectedRef.current = 0;
    scoreMultiplierRef.current = 1;
    multiplierEndFrameRef.current = 0;
    shakeRef.current = 0;

    setScore(0);
    setItemsCollected(0);
    setHasShield(false);
    setScoreMultiplier(1);
  }, [setScore, setItemsCollected, setHasShield, setScoreMultiplier]);

  // --- Helper Functions ---

  const spawnObstacle = (width: number) => {
    const laneWidth = width / GAME_CONFIG.LANE_COUNT;
    const typeRoll = Math.random();
    let type = ObstacleType.BLOCK;

    // Difficulty progression
    if (scoreRef.current > 500 && typeRoll > 0.6) type = ObstacleType.MOVING_BLOCK;
    if (scoreRef.current > 1000 && typeRoll > 0.8) type = ObstacleType.ROTATING_SPIKE;
    if (scoreRef.current > 1500 && typeRoll > 0.85) type = ObstacleType.GAP_WALL;
    if (scoreRef.current > 2000 && typeRoll > 0.90) type = ObstacleType.LASER_BEAM;

    const id = Math.random().toString(36).substr(2, 9);
    const y = -100;

    if (type === ObstacleType.GAP_WALL) {
       const gapWidth = laneWidth * 1.5;
       const gapX = Math.random() * (width - gapWidth);
       obstaclesRef.current.push({
         id: `${id}-1`, x: 0, y, width: gapX, height: 40, 
         speed: 0, type, passed: false
       });
       obstaclesRef.current.push({
         id: `${id}-2`, x: gapX + gapWidth, y, width: width - (gapX + gapWidth), height: 40, 
         speed: 0, type, passed: false
       });
    } else if (type === ObstacleType.MOVING_BLOCK) {
      const w = laneWidth * 0.8;
      const x = Math.random() * (width - w);
      obstaclesRef.current.push({
        id, x, y, width: w, height: 40, 
        speed: 2 + Math.random() * 2, type, passed: false,
        direction: Math.random() > 0.5 ? 1 : -1
      });
    } else if (type === ObstacleType.ROTATING_SPIKE) {
      const w = laneWidth; // Diameter
      const lane = Math.floor(Math.random() * GAME_CONFIG.LANE_COUNT);
      const x = (lane * laneWidth) + (laneWidth - w)/2;
      obstaclesRef.current.push({
        id, x, y, width: w, height: w,
        speed: 0, type, passed: false,
        rotation: 0
      });
    } else if (type === ObstacleType.LASER_BEAM) {
      const w = width * 0.6; // Partial width beam
      const x = Math.random() * (width - w);
      obstaclesRef.current.push({
        id, x, y, width: w, height: 20, // Height is trigger area
        speed: 0, type, passed: false,
        laserState: 'WARNING',
        laserTimer: 60 // frames warning
      });
    } else {
      // Standard Blocks
      const count = Math.floor(Math.random() * 2) + 1;
      for(let i=0; i<count; i++) {
         const w = laneWidth * 0.8;
         const lane = Math.floor(Math.random() * GAME_CONFIG.LANE_COUNT);
         const x = (lane * laneWidth) + (laneWidth - w)/2;
         if (!obstaclesRef.current.some(o => Math.abs(o.y - y) < 10 && Math.abs(o.x - x) < 10)) {
            obstaclesRef.current.push({
              id: `${id}-${i}`, x, y, width: w, height: 40 + Math.random() * 40, 
              speed: 0, type, passed: false
            });
         }
      }
    }

    if (Math.random() < 0.1) {
       const pX = Math.random() * (width - 40) + 20;
       const rand = Math.random();
       let pType = PowerUpType.SCORE_BOOST;

       if (rand > 0.75) pType = PowerUpType.SHIELD;
       else if (rand > 0.5) pType = PowerUpType.SCORE_MULTIPLIER;

       powerUpsRef.current.push({
         id: Math.random().toString(),
         x: pX, y: y - 100, radius: 15,
         type: pType, active: true
       });
    }
  };

  const createBurst = (x: number, y: number, color: string, count: number) => {
    for (let i = 0; i < count; i++) {
      const angle = Math.random() * Math.PI * 2;
      const speed = Math.random() * 6 + 2;
      particlesRef.current.push({
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 1.0,
        color,
        size: Math.random() * 3 + 2
      });
    }
  };

  const checkCollision = (obs: Obstacle, circle: Player) => {
    if (obs.type === ObstacleType.ROTATING_SPIKE) {
      // Circle collision
      const radius = obs.width / 2;
      const centerX = obs.x + radius;
      const centerY = obs.y + radius;
      const dx = circle.x - centerX;
      const dy = circle.y - centerY;
      const distance = Math.sqrt(dx*dx + dy*dy);
      return distance < (radius * 0.8 + circle.radius); // 0.8 for forgiving hitbox on spikes
    } 
    else if (obs.type === ObstacleType.LASER_BEAM) {
      if (obs.laserState !== 'ACTIVE') return false;
      // Standard Rect collision
      const clampX = Math.max(obs.x, Math.min(circle.x, obs.x + obs.width));
      const clampY = Math.max(obs.y, Math.min(circle.y, obs.y + obs.height));
      const dx = circle.x - clampX;
      const dy = circle.y - clampY;
      return (dx * dx + dy * dy) < (circle.radius * circle.radius);
    } 
    else {
      // Standard Rect collision
      const clampX = Math.max(obs.x, Math.min(circle.x, obs.x + obs.width));
      const clampY = Math.max(obs.y, Math.min(circle.y, obs.y + obs.height));
      const dx = circle.x - clampX;
      const dy = circle.y - clampY;
      return (dx * dx + dy * dy) < (circle.radius * circle.radius);
    }
  };

  const checkCircleCollision = (p1: {x: number, y: number, radius: number}, p2: {x: number, y: number, radius: number}) => {
     const dx = p1.x - p2.x;
     const dy = p1.y - p2.y;
     const dist = Math.sqrt(dx*dx + dy*dy);
     return dist < (p1.radius + p2.radius);
  };

  // --- Main Loop ---

  const update = (deltaTime: number, frameCount: number) => {
    if (!canvasRef.current) return;
    const canvas = canvasRef.current;
    const width = canvas.width;
    const height = canvas.height;

    // Shake Decay
    if (shakeRef.current > 0) {
      shakeRef.current = Math.max(0, shakeRef.current - 1);
    }

    scrollSpeedRef.current = Math.min(
      GAME_CONFIG.MAX_SCROLL_SPEED, 
      scrollSpeedRef.current + GAME_CONFIG.SPEED_INCREMENT
    );

    scoreRef.current += (scrollSpeedRef.current / 10) * scoreMultiplierRef.current;
    setScore(scoreRef.current); 

    if (scoreMultiplierRef.current > 1 && frameCount > multiplierEndFrameRef.current) {
       scoreMultiplierRef.current = 1;
       setScoreMultiplier(1);
    }

    // --- Control Logic ---
    let dx = 0;

    // 1. Keyboard
    if (keysPressed.current['ArrowLeft'] || keysPressed.current['a'] || keysPressed.current['A']) dx -= 1;
    if (keysPressed.current['ArrowRight'] || keysPressed.current['d'] || keysPressed.current['D']) dx += 1;

    // 2. Mobile Controls
    if (controlMode === ControlMode.TILT) {
      const deadzone = 2;
      const sensitivity = 0.05;
      let val = tiltGamma.current;
      if (Math.abs(val) > deadzone) {
         dx += val * sensitivity; 
      }
    } else {
      if (touchX.current !== null) {
         const diff = touchX.current - playerRef.current.x;
         const threshold = 10;
         if (Math.abs(diff) > threshold) {
            dx += Math.sign(diff); 
         }
      }
    }

    if (controlMode !== ControlMode.TILT) {
        dx = Math.max(-1, Math.min(1, dx));
    } else {
        dx = Math.max(-2, Math.min(2, dx)); 
    }

    playerRef.current.x += dx * playerRef.current.speed;

    if (playerRef.current.x < playerRef.current.radius) playerRef.current.x = playerRef.current.radius;
    if (playerRef.current.x > width - playerRef.current.radius) playerRef.current.x = width - playerRef.current.radius;

    // Enhanced Trail
    playerRef.current.trail.push({ x: playerRef.current.x, y: playerRef.current.y });
    if (playerRef.current.trail.length > 20) playerRef.current.trail.shift();

    // Spawn
    if (frameCount % Math.floor(GAME_CONFIG.OBSTACLE_SPAWN_RATE * (5 / scrollSpeedRef.current)) === 0) {
      spawnObstacle(width);
    }

    // Obstacles
    for (let i = obstaclesRef.current.length - 1; i >= 0; i--) {
      const obs = obstaclesRef.current[i];
      obs.y += scrollSpeedRef.current;

      // Type-specific updates
      if (obs.type === ObstacleType.MOVING_BLOCK && obs.direction) {
        obs.x += obs.speed * obs.direction;
        if (obs.x <= 0 || obs.x + obs.width >= width) {
          obs.direction *= -1;
        }
      } else if (obs.type === ObstacleType.ROTATING_SPIKE) {
        obs.rotation = (obs.rotation || 0) + 0.1;
      } else if (obs.type === ObstacleType.LASER_BEAM && obs.laserTimer !== undefined) {
        obs.laserTimer--;
        if (obs.laserTimer <= 0) {
           if (obs.laserState === 'WARNING') {
             obs.laserState = 'ACTIVE';
             obs.laserTimer = 40; // Active for 40 frames
           } else if (obs.laserState === 'ACTIVE') {
             obs.laserState = 'COOLDOWN';
           }
        }
      }

      if (checkCollision(obs, playerRef.current)) {
         if (playerRef.current.shieldActive) {
            playerRef.current.shieldActive = false;
            setHasShield(false);
            createBurst(obs.x + obs.width/2, obs.y + obs.height/2, GAME_CONFIG.COLORS.OBSTACLE, 20);
            obstaclesRef.current.splice(i, 1);
            continue;
         } else {
            shakeRef.current = 20; 
            setGameState(GameState.GAME_OVER);
            createBurst(playerRef.current.x, playerRef.current.y, GAME_CONFIG.COLORS.PLAYER, 50);
            return;
         }
      }
      if (obs.y > height) obstaclesRef.current.splice(i, 1);
    }

    // PowerUps
    for (let i = powerUpsRef.current.length - 1; i >= 0; i--) {
      const p = powerUpsRef.current[i];
      p.y += scrollSpeedRef.current;

      if (checkCircleCollision(playerRef.current, p)) {
        itemsCollectedRef.current++;
        setItemsCollected(itemsCollectedRef.current);

        let burstColor = GAME_CONFIG.COLORS.POWERUP_SCORE;
        if (p.type === PowerUpType.SHIELD) {
          playerRef.current.shieldActive = true;
          setHasShield(true);
          burstColor = GAME_CONFIG.COLORS.POWERUP_SHIELD;
        } else if (p.type === PowerUpType.SCORE_BOOST) {
          scoreRef.current += 500 * scoreMultiplierRef.current;
          burstColor = GAME_CONFIG.COLORS.POWERUP_SCORE;
        } else if (p.type === PowerUpType.SCORE_MULTIPLIER) {
          scoreMultiplierRef.current = 2;
          multiplierEndFrameRef.current = frameCount + 600;
          setScoreMultiplier(2);
          burstColor = GAME_CONFIG.COLORS.POWERUP_MULTIPLIER;
        }

        createBurst(p.x, p.y, burstColor, 30);
        powerUpsRef.current.splice(i, 1);
      } else if (p.y > height) {
        powerUpsRef.current.splice(i, 1);
      }
    }

    // Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
       const p = particlesRef.current[i];
       p.x += p.vx;
       p.y += p.vy;
       p.life -= 0.03;
       if (p.life <= 0) particlesRef.current.splice(i, 1);
    }
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const width = canvas.width;
    const height = canvas.height;

    ctx.save(); // Save before shake

    // Apply Shake
    if (shakeRef.current > 0) {
       const dx = (Math.random() - 0.5) * shakeRef.current * 2;
       const dy = (Math.random() - 0.5) * shakeRef.current * 2;
       ctx.translate(dx, dy);
    }

    // Background
    ctx.fillStyle = GAME_CONFIG.COLORS.BACKGROUND_GRID;
    ctx.fillRect(-20, -20, width + 40, height + 40);

    // Grid
    ctx.strokeStyle = 'rgba(6, 182, 212, 0.1)';
    ctx.lineWidth = 1;
    const gridOffset = (Date.now() / 10 * scrollSpeedRef.current) % 100;

    for (let i = 0; i <= GAME_CONFIG.LANE_COUNT; i++) {
        const x = (width / GAME_CONFIG.LANE_COUNT) * i;
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, height);
        ctx.stroke();
    }
    for (let y = gridOffset - 100; y < height; y += 100) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(width, y);
        ctx.stroke();
    }

    // Particles
    particlesRef.current.forEach(p => {
       ctx.globalAlpha = p.life;
       ctx.fillStyle = p.color;
       ctx.beginPath();
       ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
       ctx.fill();
       ctx.globalAlpha = 1.0;
    });

    // PowerUps
    powerUpsRef.current.forEach(p => {
       let color = GAME_CONFIG.COLORS.POWERUP_SCORE;
       let symbol = '+';
       if (p.type === PowerUpType.SHIELD) {
          color = GAME_CONFIG.COLORS.POWERUP_SHIELD;
          symbol = 'S';
       } else if (p.type === PowerUpType.SCORE_MULTIPLIER) {
          color = GAME_CONFIG.COLORS.POWERUP_MULTIPLIER;
          symbol = 'x2';
       }

       ctx.shadowBlur = 15;
       ctx.shadowColor = color;
       ctx.fillStyle = color;
       ctx.beginPath();
       ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
       ctx.fill();

       ctx.fillStyle = '#fff';
       ctx.font = 'bold 12px Arial';
       ctx.textAlign = 'center';
       ctx.textBaseline = 'middle';
       ctx.fillText(symbol, p.x, p.y);
       ctx.shadowBlur = 0;
    });

    // Obstacles
    obstaclesRef.current.forEach(obs => {
      if (obs.type === ObstacleType.ROTATING_SPIKE) {
         // Draw Spike
         const radius = obs.width / 2;
         const cx = obs.x + radius;
         const cy = obs.y + radius;

         ctx.save();
         ctx.translate(cx, cy);
         ctx.rotate(obs.rotation || 0);

         ctx.shadowBlur = 10;
         ctx.shadowColor = GAME_CONFIG.COLORS.OBSTACLE_GLOW;
         ctx.fillStyle = GAME_CONFIG.COLORS.OBSTACLE_SPIKE;

         // Star shape
         ctx.beginPath();
         for (let i = 0; i < 8; i++) {
            ctx.rotate(Math.PI / 4);
            ctx.lineTo(radius, 0);
            ctx.lineTo(radius * 0.5, radius * 0.2);
         }
         ctx.closePath();
         ctx.fill();

         // Inner circle
         ctx.fillStyle = '#9f1239'; // Darker rose
         ctx.beginPath();
         ctx.arc(0, 0, radius * 0.4, 0, Math.PI * 2);
         ctx.fill();

         ctx.restore();

      } else if (obs.type === ObstacleType.LASER_BEAM) {
         // Draw Laser
         if (obs.laserState === 'WARNING') {
            ctx.setLineDash([10, 10]);
            ctx.strokeStyle = GAME_CONFIG.COLORS.LASER_WARNING;
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(obs.x, obs.y + obs.height/2);
            ctx.lineTo(obs.x + obs.width, obs.y + obs.height/2);
            ctx.stroke();
            ctx.setLineDash([]);
         } else if (obs.laserState === 'ACTIVE') {
            ctx.shadowBlur = 20;
            ctx.shadowColor = GAME_CONFIG.COLORS.LASER_ACTIVE;
            ctx.fillStyle = GAME_CONFIG.COLORS.LASER_ACTIVE;
            ctx.fillRect(obs.x, obs.y, obs.width, obs.height);

            // Core
            ctx.fillStyle = '#fff';
            ctx.fillRect(obs.x, obs.y + obs.height/2 - 2, obs.width, 4);
         }

         // Emitters
         ctx.fillStyle = '#334155';
         ctx.fillRect(obs.x - 5, obs.y - 5, 5, obs.height + 10);
         ctx.fillRect(obs.x + obs.width, obs.y - 5, 5, obs.height + 10);

         ctx.shadowBlur = 0;
      } else {
         // Standard Block
         ctx.shadowBlur = 10;
         ctx.shadowColor = GAME_CONFIG.COLORS.OBSTACLE_GLOW;
         ctx.fillStyle = GAME_CONFIG.COLORS.OBSTACLE;
         ctx.beginPath();
         ctx.roundRect(obs.x, obs.y, obs.width, obs.height, 4);
         ctx.fill();
         ctx.shadowBlur = 0;
         ctx.fillStyle = 'rgba(255,255,255,0.2)';
         ctx.fillRect(obs.x, obs.y + 5, obs.width, 5);
      }
    });

    // Trail
    const player = playerRef.current;
    if (player.trail.length > 1) {
       for (let i = 0; i < player.trail.length - 1; i++) {
         const p1 = player.trail[i];
         const p2 = player.trail[i+1];
         const ratio = i / player.trail.length;

         ctx.beginPath();
         ctx.moveTo(p1.x, p1.y);
         ctx.lineTo(p2.x, p2.y);
         ctx.lineCap = 'round';
         ctx.strokeStyle = player.color;
         ctx.lineWidth = player.radius * 2 * ratio;
         ctx.globalAlpha = ratio * 0.5;
         ctx.stroke();
       }
       ctx.globalAlpha = 1.0;
    }

    // Player
    ctx.shadowBlur = 20;
    ctx.shadowColor = player.shieldActive ? GAME_CONFIG.COLORS.PLAYER_SHIELD : GAME_CONFIG.COLORS.PLAYER;
    ctx.fillStyle = '#fff';
    ctx.beginPath();
    ctx.arc(player.x, player.y, player.radius, 0, Math.PI * 2);
    ctx.fill();

    if (player.shieldActive) {
       ctx.strokeStyle = GAME_CONFIG.COLORS.PLAYER_SHIELD;
       ctx.lineWidth = 2;
       ctx.beginPath();
       ctx.arc(player.x, player.y, player.radius + 5, 0, Math.PI * 2);
       ctx.stroke();
    }

    ctx.shadowBlur = 0;

    ctx.restore();
  };

  const gameLoop = (time: number) => {
    if (gameState === GameState.PLAYING) {
       const deltaTime = time - lastTimeRef.current;
       lastTimeRef.current = time;
       update(deltaTime, Math.floor(time / 16)); 
    }
    draw();
    requestRef.current = requestAnimationFrame(gameLoop);
  };

  // --- Effects ---

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => keysPressed.current[e.key] = true;
    const handleKeyUp = (e: KeyboardEvent) => keysPressed.current[e.key] = false;

    const handleOrientation = (e: DeviceOrientationEvent) => {
      if (e.gamma !== null) tiltGamma.current = e.gamma;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('deviceorientation', handleOrientation);

    initGame();
    requestRef.current = requestAnimationFrame(gameLoop);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('deviceorientation', handleOrientation);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [initGame]); 

  useEffect(() => {
     if (gameState === GameState.PLAYING && scoreRef.current === 0) {
        initGame();
     }
  }, [gameState, initGame]);

  const handleTouchStart = (e: React.TouchEvent) => {
    touchX.current = e.touches[0].clientX;
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    touchX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = () => {
    touchX.current = null;
  };

  return (
    <div ref={containerRef} className="absolute inset-0 w-full h-full bg-slate-900">
      <canvas
        ref={canvasRef}
        className="block w-full h-full touch-none"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
      />
    </div>
  );
};

